fn extract_bytes(args: &[magnus::Value]) -> Result<ExtractionResult, Error> {
    let args = magnus::scan_args::scan_args::<(Vec<u8>, String), (Option<magnus::Value>,), (), (), (), ()>(args)?;
    let (content, mime_type) = args.required;
    let (config,) = args.optional;
    let config_core: kreuzberg::ExtractionConfig = match config {
        Some(_v) if !_v.is_nil() => {
            let binding_val: ExtractionConfig = ExtractionConfig::try_convert(_v).map_err(|e| {
                magnus::Error::new(
                    unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
                    e.to_string(),
                )
            })?;
            binding_val.into()
        }
        _ => Default::default(),
    };
    let rt = tokio::runtime::Runtime::new().map_err(|e| {
        magnus::Error::new(
            unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
            e.to_string(),
        )
    })?;
    let result = rt
        .block_on(async { kreuzberg::extract_bytes(&content, &mime_type, &config_core).await })
        .map_err(|e| {
            magnus::Error::new(
                unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
                e.to_string(),
            )
        })?;
    Ok(result.into())
}

