fn extract_file(args: &[magnus::Value]) -> Result<ExtractionResult, Error> {
    let args = magnus::scan_args::scan_args::<(String,), (Option<magnus::Value>, Option<magnus::Value>), (), (), (), ()>(
        args,
    )?;
    let (path,) = args.required;
    let (mime_type, config) = args.optional;
    let mime_type: Option<String> = mime_type.and_then(|v| {
        if v.is_nil() {
            None
        } else {
            Some(String::try_convert(v).unwrap_or_default())
        }
    });
    let config_core: kreuzberg::ExtractionConfig = match config {
        Some(_v) if !_v.is_nil() => {
            let binding_val: ExtractionConfig = ExtractionConfig::try_convert(_v).map_err(|e| {
                magnus::Error::new(
                    unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
                    e.to_string(),
                )
            })?;
            binding_val.into()
        }
        _ => Default::default(),
    };
    let rt = tokio::runtime::Runtime::new().map_err(|e| {
        magnus::Error::new(
            unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
            e.to_string(),
        )
    })?;
    let result = rt
        .block_on(async {
            kreuzberg::extract_file(std::path::PathBuf::from(path), mime_type.as_deref(), &config_core).await
        })
        .map_err(|e| {
            magnus::Error::new(
                unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
                e.to_string(),
            )
        })?;
    Ok(result.into())
}

