pub fn register_ocr_backend(rb_obj: magnus::Value, name: String) -> Result<(), magnus::Error> {
    let required_methods = ["process_image", "supports_language", "backend_type"];
    for method in &required_methods {
        if !rb_obj.respond_to(*method, false).unwrap_or(false) {
            let ruby = unsafe { magnus::Ruby::get_unchecked() };
            return Err(magnus::Error::new(
                ruby.exception_runtime_error(),
                format!("Backend missing required method: {}", method),
            ));
        }
    }

    let wrapper = RbOcrBackendBridge::new(rb_obj, name)?;
    let arc: Arc<dyn kreuzberg::plugins::OcrBackend> = Arc::new(wrapper);
    kreuzberg::plugins::registry::get_ocr_backend_registry()
        .write()
        .register(arc)
        .map_err(|e| {
            let ruby = unsafe { magnus::Ruby::get_unchecked() };
            magnus::Error::new(ruby.exception_runtime_error(), format!("register failed: {}", e))
        })?;
    Ok(())
}

